using namespace std;

const int N=32e4;



int l[N],r[N];

int vl[N],vr[N];

int t[N];

int main(){

	ios::sync_with_stdio(0);

	int n;

	cin>>n;

	for(int i=0;i<n;i++){

		cin>>l[i]>>r[i];

		vl[i]=l[i], vr[i]=r[i];

		t[l[i]]++, t[r[i]]--;

	}

	int a1=0,a2=0;

	for(int i=1;i<N;i++){

		t[i]+=t[i-1];

		a2=max(a2,t[i]);

	}

	sort(vl,vl+n);

	sort(vr,vr+n);

	for(int i=0;i<n;i++){

		int u=n-(lower_bound(vl,vl+n,r[i])-vl),

			v=upper_bound(vr,vr+n,l[i])-vr;

		a1=max(a1,n-u-v);

	}

	cout<<a1<<' '<<a2<<'\n';

	return 0;

}

