int main()

{

	int n, ans1 = 0, ans2 = 0;

	scanf("%d", &n);

	for(int i = 0; i < n; ++i) {

		scanf("%d %d", &l[i], &r[i]);

		++sum[l[i]];

		--sum[r[i]];

		++ml[l[i]];

		++mr[r[i]];

	}

	for(int i = 1; i < maxn; ++i) {

		sum[i] += sum[i - 1];

		ml[i] += ml[i - 1];

		mr[i] += mr[i - 1];

		ans2 = max(ans2, sum[i]);

	}

	for(int i = 0; i < n; ++i) {

		ans1 = max(ans1, ml[r[i] - 1] - mr[l[i]]);

	}

	printf("%d %d\n", ans1, ans2);

	return 0;

}

