using namespace std;



const int maxn = 200000 + 10;

struct Node {

    int l,r;

    bool operator < (const Node& b) const {

        return r == b.r && l > b.l || r < b.r;

    }

}P[maxn];

vector<int> sl,sr;

int n;



int main() {

    scanf("%d",&n);

    for(int i = 0; i < n; i++) {

        scanf("%d %d",&P[i].l,&P[i].r);

        sl.push_back(P[i].l);

        sr.push_back(P[i].r);

    }

    sort(sl.begin(),sl.end());

    sort(sr.begin(),sr.end());

    int mmax = 0;

    for(int i = 0; i < n; i++) {

        int t1 = upper_bound(sr.begin(),sr.end(),P[i].l) - sr.begin();

        int t2 = lower_bound(sl.begin(),sl.end(),P[i].r) - sl.begin();

        t2 = n - t2;

        mmax = max(mmax,n - t1 - t2);

    }

    sort(P, P + n);

    multiset<int> s;

    multiset<int>::iterator it;

    for(int i = 0; i < n; i++) {

        if(s.empty()) {

            s.insert(-P[i].r);

        } else {

            it = s.lower_bound(-P[i].l);

            if(it == s.end()) {

                s.insert(-P[i].r);

            } else {

                s.erase(it);

                s.insert(-P[i].r);

            }

        }

    }

    cout << mmax << " " << s.size() << endl;

    return 0;

}

