                        continue;



                    int cost2 = cost + abs(pos - i) + abs(i - j);

                    bitset<16> bs2 = bs;

                    bs2[i] = !bs2[i];

                    bs2[j] = !bs2[j];

                    if(cost2 < memo[bs2.to_ulong()][j]){

                        memo[bs2.to_ulong()][j] = cost2;

                        mm.insert(make_pair(cost2, make_pair(bs2, j)));

                    }

                }

            }

        }

    }

}

